      walk(dir);
      if (found) fail(rule.id, `PERTURBATION token found in:\n${found}`);
    }
  } else if (rule.type === 'verification-isolation') {
    // Check that no .instrument dir exists in parent of project root (or any sibling)
    const parent = path.dirname(root);
    const siblings = fs.readdirSync(parent);
    for (const sib of siblings) {
      if (sib === path.basename(root)) continue;  // skip self
      const sibPath = path.join(parent, sib);
